#include <stdio.h>
int main() {
    int n;
    scanf("%d", &n);
    int x = 0;
    for (int i = 0; i < n; i++) {
        char op[4];
        scanf("%s", op);
        if (op[0] == '+') x++;
        if (op[2] == '+') x++;
    }
    printf("X = %d\n", x);
    return 0;
}

